namespace LifeOS.Data
{
    [CreateAssetMenu(fileName = "ActivityCatalog", menuName = "LifeOS/Activity Catalog")]
    public class ActivityCatalog : ScriptableObject
    {
        public List<ActivityDefinition> activities = new List<ActivityDefinition>();

        public ActivityDefinition FindById(string activityTypeId)
        {
            if (string.IsNullOrEmpty(activityTypeId))
            {
                return null;
            }

            for (var i = 0; i < activities.Count; i++)
            {
                var activity = activities[i];
                if (activity != null && activity.activityTypeId == activityTypeId)
                {
                    return activity;
                }
            }

            return null;
        }
    }
}

