namespace LifeOS.Systems
{
    public class TimelineCoordinator
    {
        readonly RealTimelineStore _realTimeline;
        readonly SimulationTimelineStore _simulationTimeline;
        readonly BehaviorGrowthBridge _growthBridge;
        readonly BehaviorAnalyticsExporter _analyticsExporter;

        public RealTimelineStore RealTimeline => _realTimeline;
        public SimulationTimelineStore SimulationTimeline => _simulationTimeline;
        public BehaviorGrowthBridge GrowthBridge => _growthBridge;
        public BehaviorAnalyticsExporter AnalyticsExporter => _analyticsExporter;

        public TimelineCoordinator(
            RealTimelineStore realTimeline = null,
            SimulationTimelineStore simulationTimeline = null,
            ActivityCatalog activityCatalog = null)
        {
            _realTimeline = realTimeline ?? new RealTimelineStore();
            _simulationTimeline = simulationTimeline ?? new SimulationTimelineStore();
            _growthBridge = new BehaviorGrowthBridge(activityCatalog);
            _analyticsExporter = new BehaviorAnalyticsExporter();
        }

        public BehaviorRecord LogActivity(BehaviorRecord record, ActivityDefinition definition = null)
        {
            definition?.ApplyDefaultsTo(record);
            var logged = _realTimeline.LogActivity(record);
            _growthBridge.EmitGrowthEvents(logged);
            return logged;
        }

        public List<GrowthEvent> LogActivityWithGrowthEvents(
            string title,
            float durationHours,
            LifeDomain domain,
            int focus,
            int intensity,
            int cognitiveLoad,
            int energyCost,
            int mood,
            DateTime? startTimeLocal = null,
            string activityTypeId = "",
            string linkedGoalId = "",
            string linkedTaskId = "",
            string primarySkillId = "",
            ActivityDefinition definition = null)
        {
            var record = BehaviorRecord.CreateLogged(
                title,
                durationHours,
                domain,
                focus,
                intensity,
                cognitiveLoad,
                energyCost,
                mood,
                startTimeLocal ?? LifeTime.Now,
                activityTypeId,
                linkedGoalId,
                linkedTaskId,
                primarySkillId);

            definition?.ApplyDefaultsTo(record);
            _realTimeline.LogActivity(record);
            return _growthBridge.EmitGrowthEvents(record);
        }

        public PlanDraft AddSimulationDraft(PlanDraft draft, ActivityDefinition definition = null)
        {
            definition?.ApplyDefaultsTo(draft);
            return _simulationTimeline.AddDraft(draft);
        }

        public BehaviorRecord AdoptSimulatedPlan(string draftId)
        {
            var draft = _simulationTimeline.FindById(draftId);
            if (draft == null)
            {
                return null;
            }

            var plannedStartLocal = draft.GetPlannedStartLocal(_simulationTimeline.Anchor.AnchorLocal);
            var plannedRecord = _realTimeline.AddPlanned(draft, plannedStartLocal);
            _simulationTimeline.Remove(draftId);
            return plannedRecord;
        }

        public List<BehaviorRecord> AdoptAllSimulatedPlans()
        {
            var adopted = new List<BehaviorRecord>();
            var drafts = _simulationTimeline.GetOrderedDrafts();

            foreach (var draft in drafts)
            {
                var plannedRecord = AdoptSimulatedPlan(draft.id);
                if (plannedRecord != null)
                {
                    adopted.Add(plannedRecord);
                }
            }

            return adopted;
        }

        public List<GrowthEvent> ConfirmPlannedActivity(string realRecordId, DateTime? actualStartLocal = null)
        {
            var record = _realTimeline.FindById(realRecordId);
            if (record == null || record.status != ActivityStatus.Planned)
            {
                return new List<GrowthEvent>();
            }

            _realTimeline.MarkAsLogged(realRecordId, actualStartLocal ?? record.GetStartTimeLocal());
            var confirmed = _realTimeline.FindById(realRecordId);
            return _growthBridge.EmitGrowthEvents(confirmed);
        }

        public BehaviorPeriodSnapshot ExportBehaviorSnapshot(DateTime periodStartLocal, DateTime periodEndLocal)
        {
            return _analyticsExporter.Export(_realTimeline, periodStartLocal, periodEndLocal);
        }

        public void SaveAll()
        {
            _realTimeline.Save();
            _simulationTimeline.Save();
        }
    }
}

