namespace LifeOS.Data
{
    [CreateAssetMenu(fileName = "ActivityDefinition", menuName = "LifeOS/Activity Definition")]
    public class ActivityDefinition : ScriptableObject
    {
        public string activityTypeId;
        public string displayName;
        public LifeDomain domain;
        public string defaultSkillId;
        public float xpPerHour = 10f;

        [Header("Default Semantics (1-5, 0 = unset)")]
        public int defaultFocus;
        public int defaultIntensity;
        public int defaultCognitiveLoad;
        public int defaultEnergyCost;
        public int defaultMood;

        public void ApplyDefaultsTo(BehaviorRecord record)
        {
            if (record == null)
            {
                return;
            }

            if (string.IsNullOrEmpty(record.activityTypeId))
            {
                record.activityTypeId = activityTypeId;
            }

            if (!string.IsNullOrEmpty(displayName) && string.IsNullOrEmpty(record.title))
            {
                record.title = displayName;
            }

            record.domain = domain;

            if (record.focus == 0)
            {
                record.focus = defaultFocus;
            }

            if (record.intensity == 0)
            {
                record.intensity = defaultIntensity;
            }

            if (record.cognitiveLoad == 0)
            {
                record.cognitiveLoad = defaultCognitiveLoad;
            }

            if (record.energyCost == 0)
            {
                record.energyCost = defaultEnergyCost;
            }

            if (record.mood == 0)
            {
                record.mood = defaultMood;
            }

            if (string.IsNullOrEmpty(record.primarySkillId))
            {
                record.primarySkillId = defaultSkillId;
            }
        }

        public void ApplyDefaultsTo(PlanDraft draft)
        {
            if (draft == null)
            {
                return;
            }

            if (string.IsNullOrEmpty(draft.activityTypeId))
            {
                draft.activityTypeId = activityTypeId;
            }

            if (!string.IsNullOrEmpty(displayName) && string.IsNullOrEmpty(draft.title))
            {
                draft.title = displayName;
            }

            draft.domain = domain;

            if (draft.focus == 0)
            {
                draft.focus = defaultFocus;
            }

            if (draft.intensity == 0)
            {
                draft.intensity = defaultIntensity;
            }

            if (draft.cognitiveLoad == 0)
            {
                draft.cognitiveLoad = defaultCognitiveLoad;
            }

            if (draft.energyCost == 0)
            {
                draft.energyCost = defaultEnergyCost;
            }

            if (draft.mood == 0)
            {
                draft.mood = defaultMood;
            }

            if (string.IsNullOrEmpty(draft.primarySkillId))
            {
                draft.primarySkillId = defaultSkillId;
            }
        }

        public float CalculateXpGain(float durationHours)
        {
            return durationHours * xpPerHour;
        }
    }
}

