    public class SimulationTimelineStore
    {
        const string FileName = "sim_timeline.json";

        readonly string _filePath;
        readonly PlanDraftDatabase _database = new PlanDraftDatabase();
        readonly SimulationAnchor _anchor = new SimulationAnchor();

        public IReadOnlyList<PlanDraft> Entries => _database.entries;
        public SimulationAnchor Anchor => _anchor;

        public SimulationTimelineStore(string storageDirectory = null)
        {
            var directory = storageDirectory ?? JsonFileStorage.GetDefaultStorageDirectory();
            _filePath = System.IO.Path.Combine(directory, FileName);
            Load();
        }

        public PlanDraft AddDraft(PlanDraft draft)
        {
            _database.entries.Add(draft);
            Save();
            return draft;
        }

        public PlanDraft AddDraft(
            string title,
            float durationHours,
            LifeDomain domain,
            int focus,
            int intensity,
            int cognitiveLoad,
            int energyCost,
            int mood,
            int plannedOffsetMinutes,
            string activityTypeId = "",
            string linkedGoalId = "",
            string linkedTaskId = "",
            string primarySkillId = "")
        {
            var draft = PlanDraft.Create(
                title,
                durationHours,
                domain,
                focus,
                intensity,
                cognitiveLoad,
                energyCost,
                mood,
                plannedOffsetMinutes,
                activityTypeId,
                linkedGoalId,
                linkedTaskId,
                primarySkillId);

            return AddDraft(draft);
        }

        public bool Update(PlanDraft updatedDraft)
        {
            var index = _database.entries.FindIndex(draft => draft.id == updatedDraft.id);
            if (index < 0)
            {
                return false;
            }

            _database.entries[index] = updatedDraft;
            Save();
            return true;
        }

        public bool Remove(string id)
        {
            var removed = _database.entries.RemoveAll(draft => draft.id == id) > 0;
            if (removed)
            {
                Save();
            }

            return removed;
        }

        public PlanDraft FindById(string id)
        {
            return _database.entries.FirstOrDefault(draft => draft.id == id);
        }

        public List<PlanDraft> GetOrderedDrafts()
        {
            return _database.entries
                .OrderBy(draft => draft.plannedOffsetMinutes)
                .ToList();
        }

        public void Clear()
        {
            _database.entries.Clear();
            Save();
        }

        public void SetAnchor(DateTime anchorLocal)
        {
            _anchor.SetAnchor(anchorLocal);
            Save();
        }

        public void Save()
        {
            _database.anchorTimeLocal = _anchor.AnchorTimeLocalString;
            JsonFileStorage.Save(_filePath, _database);
        }

        public void Load()
        {
            var loaded = JsonFileStorage.Load<PlanDraftDatabase>(_filePath);
            _database.entries = loaded.entries ?? new List<PlanDraft>();

            if (!string.IsNullOrEmpty(loaded.anchorTimeLocal))
            {
                _anchor.SetAnchor(LifeTime.ParseLocal(loaded.anchorTimeLocal));
            }
        }
    }
}

