        public static BehaviorRecord CreateLogged(
            string title,
            float durationHours,
            LifeDomain domain,
            int focus,
            int intensity,
            int cognitiveLoad,
            int energyCost,
            int mood,
            DateTime startTimeLocal,
            string activityTypeId = "",
            string linkedGoalId = "",
            string linkedTaskId = "",
            string primarySkillId = "")
        {
            return new BehaviorRecord
            {
                id = Guid.NewGuid().ToString(),
                title = title,
                activityTypeId = activityTypeId ?? string.Empty,
                duration = durationHours,
                domain = domain,
                focus = focus,
                intensity = intensity,
                cognitiveLoad = cognitiveLoad,
                energyCost = energyCost,
                mood = mood,
                linkedGoalId = linkedGoalId ?? string.Empty,
                linkedTaskId = linkedTaskId ?? string.Empty,
                primarySkillId = primarySkillId ?? string.Empty,
                status = ActivityStatus.Logged,
                startTimeLocal = LifeTime.FormatLocal(startTimeLocal)
            };
        }

        public static BehaviorRecord FromPlanDraft(PlanDraft draft, DateTime plannedStartLocal)
        {
            return new BehaviorRecord
            {
                id = Guid.NewGuid().ToString(),
                title = draft.title,
                activityTypeId = draft.activityTypeId,
                duration = draft.duration,
                domain = draft.domain,
                focus = draft.focus,
                intensity = draft.intensity,
                cognitiveLoad = draft.cognitiveLoad,
                energyCost = draft.energyCost,
                mood = draft.mood,
                linkedGoalId = draft.linkedGoalId,
                linkedTaskId = draft.linkedTaskId,
                primarySkillId = draft.primarySkillId,
                status = ActivityStatus.Planned,
                startTimeLocal = LifeTime.FormatLocal(plannedStartLocal)
            };
        }

        public DateTime GetStartTimeLocal()
        {
            if (string.IsNullOrEmpty(startTimeLocal))
            {
                return DateTime.MinValue;
            }

            return LifeTime.ParseLocal(startTimeLocal);
        }

        public void SetStartTimeLocal(DateTime time)
        {
            startTimeLocal = LifeTime.FormatLocal(time);
        }

        public bool IsBehaviorFact()
        {
            return status == ActivityStatus.Logged;
        }
    }
