namespace LifeOS.Systems
{
    public class BehaviorGrowthBridge
    {
        readonly ActivityCatalog _catalog;
        const float DefaultXpPerHour = 5f;

        public BehaviorGrowthBridge(ActivityCatalog catalog = null)
        {
            _catalog = catalog;
        }

        public List<GrowthEvent> EmitGrowthEvents(BehaviorRecord record)
        {
            var events = new List<GrowthEvent>();

            if (record == null || !record.IsBehaviorFact())
            {
                return events;
            }

            var definition = _catalog?.FindById(record.activityTypeId);
            var skillId = !string.IsNullOrEmpty(record.primarySkillId)
                ? record.primarySkillId
                : definition?.defaultSkillId;

            if (string.IsNullOrEmpty(skillId))
            {
                return events;
            }

            var xpPerHour = definition != null ? definition.xpPerHour : DefaultXpPerHour;
            var xpGained = record.duration * xpPerHour;
            var progressDelta = string.IsNullOrEmpty(record.linkedGoalId) ? 0f : 1f;
            events.Add(GrowthEvent.Create(record, skillId, xpGained, progressDelta));

            return events;
        }
    }
}

