namespace LifeOS.Systems
{
    public class BehaviorAnalyticsExporter
    {
        public BehaviorPeriodSnapshot Export(RealTimelineStore store, DateTime periodStartLocal, DateTime periodEndLocal)
        {
            var facts = store.GetBehaviorFactsBetween(periodStartLocal, periodEndLocal);
            var snapshot = new BehaviorPeriodSnapshot
            {
                periodStartLocal = LifeTime.FormatLocal(periodStartLocal),
                periodEndLocal = LifeTime.FormatLocal(periodEndLocal),
                totalEventCount = facts.Count
            };

            if (facts.Count == 0)
            {
                return snapshot;
            }

            foreach (var record in facts)
            {
                snapshot.events.Add(BehaviorEventDto.FromRecord(record));
            }

            snapshot.hoursByDomain = BuildDomainHours(facts);
            snapshot.avgMood = (float)facts.Average(record => record.mood);
            snapshot.avgEnergyCost = (float)facts.Average(record => record.energyCost);

            return snapshot;
        }

        static List<DomainHoursEntry> BuildDomainHours(List<BehaviorRecord> facts)
        {
            var hoursByDomain = new Dictionary<LifeDomain, float>();

            foreach (var record in facts)
            {
                if (!hoursByDomain.ContainsKey(record.domain))
                {
                    hoursByDomain[record.domain] = 0f;
                }

                hoursByDomain[record.domain] += record.duration;
            }

            var entries = new List<DomainHoursEntry>();
            foreach (var pair in hoursByDomain.OrderByDescending(pair => pair.Value))
            {
                entries.Add(new DomainHoursEntry
                {
                    domain = pair.Key,
                    hours = pair.Value
                });
            }

            return entries;
        }
    }
}

