    public class RealTimelineStore
    {
        const string FileName = "real_timeline.json";

        readonly string _filePath;
        readonly TimelineDatabase _database = new TimelineDatabase();

        public IReadOnlyList<BehaviorRecord> Entries => _database.entries;

        public RealTimelineStore(string storageDirectory = null)
        {
            var directory = storageDirectory ?? JsonFileStorage.GetDefaultStorageDirectory();
            _filePath = System.IO.Path.Combine(directory, FileName);
            Load();
        }

        public BehaviorRecord LogActivity(BehaviorRecord record)
        {
            record.status = ActivityStatus.Logged;
            if (string.IsNullOrEmpty(record.startTimeLocal))
            {
                record.SetStartTimeLocal(LifeTime.Now);
            }

            _database.entries.Add(record);
            Save();
            return record;
        }

        public BehaviorRecord LogActivity(
            string title,
            float durationHours,
            LifeDomain domain,
            int focus,
            int intensity,
            int cognitiveLoad,
            int energyCost,
            int mood,
            DateTime? startTimeLocal = null,
            string activityTypeId = "",
            string linkedGoalId = "",
            string linkedTaskId = "",
            string primarySkillId = "")
        {
            var record = BehaviorRecord.CreateLogged(
                title,
                durationHours,
                domain,
                focus,
                intensity,
                cognitiveLoad,
                energyCost,
                mood,
                startTimeLocal ?? LifeTime.Now,
                activityTypeId,
                linkedGoalId,
                linkedTaskId,
                primarySkillId);

            return LogActivity(record);
        }

        public BehaviorRecord AddPlanned(PlanDraft draft, DateTime plannedStartLocal)
        {
            var record = BehaviorRecord.FromPlanDraft(draft, plannedStartLocal);
            _database.entries.Add(record);
            Save();
            return record;
        }

        public bool MarkAsLogged(string id, DateTime? actualStartLocal = null)
        {
            var record = FindById(id);
            if (record == null ||
                (record.status != ActivityStatus.Planned && record.status != ActivityStatus.InProgress))
            {
                return false;
            }

            record.status = ActivityStatus.Logged;
            if (actualStartLocal.HasValue)
            {
                record.SetStartTimeLocal(actualStartLocal.Value);
            }

            Save();
            return true;
        }

        public bool Update(BehaviorRecord updatedRecord)
        {
            var index = _database.entries.FindIndex(record => record.id == updatedRecord.id);
            if (index < 0)
            {
                return false;
            }

            _database.entries[index] = updatedRecord;
            Save();
            return true;
        }

        public bool Remove(string id)
        {
            var removed = _database.entries.RemoveAll(record => record.id == id) > 0;
            if (removed)
            {
                Save();
            }

            return removed;
        }

        public BehaviorRecord FindById(string id)
        {
            return _database.entries.FirstOrDefault(record => record.id == id);
        }

        public List<BehaviorRecord> GetBetween(DateTime startLocal, DateTime endLocal)
        {
            return _database.entries
                .Where(record =>
                {
                    var start = record.GetStartTimeLocal();
                    return start >= startLocal && start <= endLocal;
                })
                .OrderBy(record => record.GetStartTimeLocal())
                .ToList();
        }

        public List<BehaviorRecord> GetBehaviorFactsBetween(DateTime startLocal, DateTime endLocal)
        {
            return GetBetween(startLocal, endLocal)
                .Where(record => record.IsBehaviorFact())
                .ToList();
        }

        public List<BehaviorRecord> GetByStatus(ActivityStatus status)
        {
            return _database.entries
                .Where(record => record.status == status)
                .OrderBy(record => record.GetStartTimeLocal())
                .ToList();
        }

        public List<BehaviorRecord> GetAllOrdered()
        {
            return _database.entries
                .OrderBy(record => record.GetStartTimeLocal())
                .ToList();
        }

        public void Save()
        {
            JsonFileStorage.Save(_filePath, _database);
        }

        public void Load()
        {
            var loaded = JsonFileStorage.Load<TimelineDatabase>(_filePath);
            _database.entries = loaded.entries ?? new List<BehaviorRecord>();
        }
    }
}

